const resp = items[0].json;
const raw =
  resp?.output?.[0]?.content?.find(c => c.type === 'output_text')?.text
  ?? resp?.output?.[0]?.content?.[0]?.text
  ?? null;

if (!raw) throw new Error('ROI Modeler: could not find output_text in API response.');

let result;
try {
  result = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch(e) {
  throw new Error('ROI Modeler: failed to parse JSON — ' + e.message);
}

return [{ json: {
  result,
  tokenTotals: {
    input:  resp?.usage?.input_tokens  ?? null,
    output: resp?.usage?.output_tokens ?? null,
  },
} }];

const modelerOut = items[0].json.result;
const analystOut  = $('Parse Company Analyst').first().json.result;

if (!modelerOut || !analystOut) throw new Error('ROI Calculator: missing upstream data.');

const profile   = analystOut.company_profile;
const workflows = analystOut.workflows;   // from Company Analyst
const wfAssumps = modelerOut.workflowAssumptions; // from ROI Modeler

// Match by name (case-insensitive) so reordering never misaligns numbers
function findAssump(wfName) {
  const lower = (wfName || '').toLowerCase();
  return wfAssumps.find(a => (a.workflowName || '').toLowerCase() === lower)
      || wfAssumps.find(a => lower.includes((a.workflowName || '').toLowerCase().slice(0, 8)))
      || wfAssumps[workflows.findIndex(w => w.name === wfName)] // index fallback
      || null;
}

const currency          = modelerOut.currency;
const hourlyCost        = modelerOut.labor.fullyLoadedHourlyCost;
const workWeeksPerYear  = modelerOut.labor.workWeeksPerYear || 48;
const realizationFactor = modelerOut.realizationFactor;
const profitMultiplier  = modelerOut.profitMultiplier;
const implCost          = modelerOut.costs.implementationCost;
const monthlyTooling    = modelerOut.costs.monthlyToolingCost;
const workingMonthFactor = workWeeksPerYear / 52;
const MAX_MIN = 480;

function calcScenario(wa, adoptionRate) {
  const netSaved = Math.max(0,
    (wa.minutesPerItemBefore - wa.minutesPerItemAfter)
    - (wa.exceptionRate * wa.exceptionMinutes)
  );
  const hrs = (wa.monthlyVolume * adoptionRate * netSaved / 60) * realizationFactor * workingMonthFactor;
  return { monthlyHours: hrs, annualHours: hrs * 12, annualValue: hrs * 12 * hourlyCost };
}

const workflowResults = [];
for (const wf of workflows) {
  const wa = { ...findAssump(wf.name) };
  if (!wa.workflowName) throw new Error('ROI Calculator: no assumption found for workflow "' + wf.name + '".');

  wa.minutesPerItemBefore = Math.min(wa.minutesPerItemBefore, MAX_MIN);
  wa.minutesPerItemAfter  = Math.min(wa.minutesPerItemAfter, wa.minutesPerItemBefore);

  const timeSaved  = wa.minutesPerItemBefore - wa.minutesPerItemAfter;
  const savingsPct = wa.minutesPerItemBefore > 0
    ? Math.round(timeSaved / wa.minutesPerItemBefore * 100) : 0;
  const costPerRun  = (wa.minutesPerItemBefore / 60) * hourlyCost;
  const monthlyCost = Math.round(wa.monthlyVolume * costPerRun);
  const base        = calcScenario(wa, wa.adoption_base);

  workflowResults.push({
    name:            wf.name,
    function:        wf.function        || 'Operations',
    owner:           wf.owner           || '—',
    agentName:       wf.agentName       || '',
    whyItMatters:    wf.whyItMatters     || '',
    expectedOutcome: wf.expectedOutcome || '',
    source:          wf.sourceType      || 'inferred',
    volume:          Math.round(wa.monthlyVolume),
    timeBefore:      wa.minutesPerItemBefore,
    timeAfter:       wa.minutesPerItemAfter,
    timeSaved:       Math.round(timeSaved),
    savingsPct,
    costPerRun:      Math.round(costPerRun),
    monthlyCost,
    monthlyHours:    Math.round(base.monthlyHours),
    monthlyValue:    Math.round(base.monthlyHours * hourlyCost),
    annualHours:     Math.round(base.annualHours),
    annualValue:     Math.round(base.annualValue),
    rate:            hourlyCost,
    rationale:       wa.rationale || '',
  });
}

// Revenue guardrail — cap at 20% of annual revenue, never inflate
const revenueM = profile.revenueEstimateM;
if (revenueM != null && revenueM > 0) {
  const rawTotal = workflowResults.reduce((s, w) => s + w.annualValue, 0);
  if (rawTotal > 0) {
    const cap    = revenueM * 1e6 * 0.20;
    const clamped = Math.round(Math.min(cap, rawTotal) / 1000) * 1000;
    const scale   = clamped / rawTotal;
    if (Math.abs(scale - 1) > 0.001) {
      workflowResults.forEach(w => {
        w.annualValue  = Math.round(w.annualValue  * scale);
        w.monthlyValue = Math.round(w.monthlyValue * scale);
        w.annualHours  = Math.round(w.annualHours  * scale);
        w.monthlyHours = Math.round(w.monthlyHours * scale);
      });
    }
  }
}

const totalMonthlyHours = workflowResults.reduce((s, w) => s + w.monthlyHours, 0);
const totalAnnualHours  = workflowResults.reduce((s, w) => s + w.annualHours,  0);
const totalAnnualValue  = workflowResults.reduce((s, w) => s + w.annualValue,  0);

const od12 = Math.round(totalAnnualValue);
const pu12 = Math.round(totalAnnualValue * (profitMultiplier - 1));
const tf12 = od12 + pu12;
const od24 = Math.round(od12 * 2.15); const pu24 = Math.round(pu12 * 2.15); const tf24 = od24 + pu24;
const od36 = Math.round(od12 * 3.40); const pu36 = Math.round(pu12 * 3.40); const tf36 = od36 + pu36;

const paybackMonths = totalAnnualValue > 0
  ? Math.ceil(implCost / (totalAnnualValue / 12)) : null;

// Enforce 6–10 month payback regardless of what modeler returned
// The modeler often underestimates implementationCost
const monthlyValue   = totalAnnualValue / 12;
const minImplCost    = Math.round(monthlyValue * 6);
const maxImplCost    = Math.round(monthlyValue * 10);
const adjImplCost    = Math.max(minImplCost, Math.min(maxImplCost, implCost));
const adjPayback     = totalAnnualValue > 0 ? Math.ceil(adjImplCost / monthlyValue) : null;

// Pre-formatted strings for Report Writer — prevents number hallucination
function addCommas(n) {
  const str = String(Math.round(+n || 0));
  let out = '';
  for (let i = 0; i < str.length; i++) {
    if (i > 0 && (str.length - i) % 3 === 0) out += ',';
    out += str[i];
  }
  return out;
}
const sym    = currency.symbol;
const fmtCur = (n) => sym + addCommas(n);
const fmtShort = (n) => {
  const v = Math.round(+n);
  if (v >= 1000000) return sym + (v / 1000000).toFixed(1) + 'M';
  if (v >= 1000)    return sym + Math.round(v / 1000) + 'K';
  return fmtCur(v);
};

const figures = {
  totalMonthlyHours:       addCommas(Math.round(totalMonthlyHours)),
  totalAnnualHours:        addCommas(Math.round(totalAnnualHours)),
  statFTE:                 (totalAnnualHours / 2000).toFixed(1),
  operationalDividend12mo: fmtCur(od12),
  profitUplift12mo:        fmtCur(pu12),
  totalFinancialGain12mo:  fmtCur(tf12),
  totalFinancialGainShort: fmtShort(tf12),
  workflowLines: workflowResults.map(w =>
    w.name + ': ' + addCommas(w.monthlyHours) + ' hrs/mo freed, ' + fmtCur(w.annualValue) + '/yr'
  ),
};

return [{ json: {
  roi_data: {
    company:       profile.company,
    industry:      profile.industry,
    country:       profile.country,
    primaryFocus:  profile.primaryFocus,
    keyPriorities: profile.keyPriorities || [],
    employees:     profile.employees,
    revenue:       profile.revenueEstimateM,
    currency,
    workflows:     workflowResults,
    totalMonthlyHours: Math.round(totalMonthlyHours),
    totalAnnualHours:  Math.round(totalAnnualHours),
    profitMultiplier,
    realizationFactor,
    workWeeksPerYear,
    summary: {
      totalAnnualHours,
      operationalDividend12mo: od12, profitUplift12mo: pu12, totalFinancialGain12mo: tf12,
      operationalDividend24mo: od24, profitUplift24mo: pu24, totalFinancialGain24mo: tf24,
      operationalDividend36mo: od36, profitUplift36mo: pu36, totalFinancialGain36mo: tf36,
      implCost: adjImplCost, monthlyTooling, paybackMonths: adjPayback,
    },
  },
  figures,
  analystData:  analystOut,
  modelerNotes: modelerOut.notes?.assumptions || [],
}}];

const resp = items[0].json;
const raw =
  resp?.output?.[0]?.content?.find(c => c.type === 'output_text')?.text
  ?? resp?.output?.[0]?.content?.[0]?.text
  ?? null;

if (!raw) throw new Error('Report Writer: could not find output_text in API response.');

let result;
try {
  result = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch(e) {
  throw new Error('Report Writer: failed to parse JSON — ' + e.message);
}

return [{ json: {
  result,
  tokenTotals: {
    input:  resp?.usage?.input_tokens  ?? null,
    output: resp?.usage?.output_tokens ?? null,
  },
} }];

// ─────────────────────────────────────────────────────────────
// ASSEMBLE REPORT
// Pulls from ROI Calculator, Parse Report Writer, Normalize Input.
// Pre-builds all display strings and table HTML.
// HTML Template node only does {{ $json.display.xxx }} lookups.
// ─────────────────────────────────────────────────────────────

// ── Source nodes ──────────────────────────────────────────────
const calcOut   = $('ROI Calculator').first().json;
const writerOut = $('Parse Report Writer').first().json.result || {};
const normInput = $('Normalize Input').first().json;

const roi        = calcOut.roi_data;
const analystData = calcOut.analystData || {};
const painPoints  = analystData.pain_points || [];
const modelerNotes = calcOut.modelerNotes  || [];
const sym         = roi.currency.symbol;
const s           = roi.summary;

// ── Formatters ────────────────────────────────────────────────
// addCommas: loop-only, no regex, no toLocaleString (PDF-safe)
function addCommas(n) {
  const str = String(Math.round(+n || 0));
  let out = '';
  for (let i = 0; i < str.length; i++) {
    if (i > 0 && (str.length - i) % 3 === 0) out += ',';
    out += str[i];
  }
  return out;
}
const fmt   = (n) => (n != null && !isNaN(+n)) ? addCommas(+n) : '—';
const cur   = (n) => sym + fmt(n);
const short = (n) => {
  if (n == null || isNaN(+n)) return '—';
  const v = Math.round(+n);
  if (v >= 1000000) return sym + (v / 1000000).toFixed(1) + 'M';
  if (v >= 1000)    return sym + Math.round(v / 1000) + 'K';
  return cur(v);
};

// ── Derived values ────────────────────────────────────────────
const tf12 = s.operationalDividend12mo + s.profitUplift12mo;

// Sort workflows by annual value descending for table display
const wfs = [...roi.workflows].sort((a, b) => b.annualValue - a.annualValue);

const totalMonthlyHours = wfs.reduce((a, w) => a + w.monthlyHours, 0);
const totalMonthlyCost  = wfs.reduce((a, w) => a + w.monthlyCost,  0);

// Function roll-up: aggregate by business function
const fnMap = {};
roi.workflows.forEach(w => {
  const fn = w.function || 'Operations';
  if (!fnMap[fn]) fnMap[fn] = { function: fn, monthlyHours: 0, rate: w.rate, monthlyValue: 0, annualValue: 0 };
  fnMap[fn].monthlyHours += w.monthlyHours;
  fnMap[fn].monthlyValue += w.monthlyValue;
  fnMap[fn].annualValue  += w.annualValue;
});
const fnRollup = Object.values(fnMap).sort((a, b) => b.annualValue - a.annualValue);

// Date — loop-only, no toLocaleDateString (PDF-safe)
const MONTHS = ['January','February','March','April','May','June',
                'July','August','September','October','November','December'];
const now = new Date();
const currentDate = MONTHS[now.getMonth()] + ' ' + now.getDate() + ', ' + now.getFullYear();

// ── HTML blocks ───────────────────────────────────────────────

// Executive summary: double-newlines → <p> tags
const execSummaryHTML = (writerOut.executiveSummary || '')
  .split(/\n\n+/)
  .filter(p => p.trim())
  .map(p => '<p style="margin-bottom:7px">' + p.replace(/\n/g, ' ').trim() + '</p>')
  .join('');

// Scope list
const scopeListHTML = wfs.map(w => '<li>' + w.name + '</li>').join('');

// As-Is Baseline table
const asisTableBody = wfs.map(wf =>
  '<tr>'
  + '<td><strong>' + wf.name + '</strong></td>'
  + '<td>' + (wf.owner || '—') + '</td>'
  + '<td style="text-align:center">' + fmt(wf.volume) + '</td>'
  + '<td style="text-align:center">' + fmt(wf.timeBefore) + ' min</td>'
  + '<td>' + sym + fmt(wf.rate) + '/hr</td>'
  + '<td>' + sym + fmt(wf.costPerRun) + '</td>'
  + '<td><strong>' + sym + fmt(wf.monthlyCost) + '</strong></td>'
  + '</tr>'
).join('')
+ '<tr class="total-row">'
  + '<td colspan="6"><strong>Total monthly run-cost</strong></td>'
  + '<td><strong>' + sym + fmt(totalMonthlyCost) + '</strong></td>'
  + '</tr>';

// Before vs After table
const bvaTableBody = wfs.map(wf =>
  '<tr>'
  + '<td><strong>' + wf.name + '</strong></td>'
  + '<td style="text-align:center">' + fmt(wf.volume) + '</td>'
  + '<td style="text-align:center">' + fmt(wf.timeBefore) + ' min</td>'
  + '<td style="text-align:center">' + fmt(wf.timeAfter) + ' min</td>'
  + '<td style="text-align:center">' + fmt(wf.timeSaved) + ' min (-' + (wf.savingsPct || 0) + '%)</td>'
  + '<td style="text-align:center">' + fmt(wf.monthlyHours) + ' hrs</td>'
  + '<td>' + sym + fmt(wf.rate) + '/hr</td>'
  + '<td class="accent">' + sym + fmt(wf.annualValue) + '</td>'
  + '</tr>'
).join('')
+ '<tr class="total-row">'
  + '<td colspan="5"><strong>Monthly capacity unlocked</strong></td>'
  + '<td><strong>' + fmt(totalMonthlyHours) + ' hrs</strong></td>'
  + '<td></td>'
  + '<td class="accent"><strong>' + sym + fmt(s.operationalDividend12mo) + '/yr</strong></td>'
  + '</tr>';

// Profit Levers table
const levers = writerOut.profit_levers || [];
const profitLeversBody = levers.map(l =>
  '<tr>'
  + '<td><strong>' + (l.lever_name || '') + '</strong></td>'
  + '<td>' + (l.baseline_data || '') + '</td>'
  + '<td>' + (l.assumption || '') + '</td>'
  + '<td>' + (l.rationale || '') + '</td>'
  + '<td class="accent"><strong>' + sym + fmt(+l.profit || 0) + '</strong></td>'
  + '</tr>'
).join('')
+ '<tr class="total-row">'
  + '<td colspan="4"><strong>12-month incremental profit</strong></td>'
  + '<td class="accent"><strong>' + sym + fmt(s.profitUplift12mo) + '</strong></td>'
  + '</tr>';

// Deploy table
const deployTableBody = wfs.map(wf =>
  '<tr>'
  + '<td><strong>' + wf.name + '</strong><br>'
  + '<span class="muted">' + (wf.expectedOutcome || '') + '</span></td>'
  + '<td class="accent"><strong>' + (wf.agentName || '') + '</strong></td>'
  + '<td>' + (wf.whyItMatters || '') + '</td>'
  + '</tr>'
).join('');

// Function Roll-Up table
const fnTotalHrs = fnRollup.reduce((a, f) => a + f.monthlyHours, 0);
const fnTotalMoV = fnRollup.reduce((a, f) => a + f.monthlyValue, 0);
const fnTotalAnV = fnRollup.reduce((a, f) => a + f.annualValue,  0);
const functionRollupBody = fnRollup.map(fn =>
  '<tr>'
  + '<td><strong>' + fn.function + '</strong></td>'
  + '<td>' + fmt(fn.monthlyHours) + ' hrs</td>'
  + '<td>' + sym + fmt(fn.rate) + '/hr</td>'
  + '<td>' + sym + fmt(fn.monthlyValue) + '</td>'
  + '<td class="accent"><strong>' + sym + fmt(fn.annualValue) + '</strong></td>'
  + '</tr>'
).join('')
+ '<tr class="total-row">'
  + '<td><strong>Total</strong></td>'
  + '<td><strong>' + fmt(fnTotalHrs) + ' hrs</strong></td>'
  + '<td></td>'
  + '<td><strong>' + sym + fmt(fnTotalMoV) + '</strong></td>'
  + '<td class="accent"><strong>' + sym + fmt(fnTotalAnV) + '</strong></td>'
  + '</tr>';

// Risks table
const risksTableBody = (writerOut.risks_mitigations || []).map(r =>
  '<tr>'
  + '<td>' + (r.risk || '') + '</td>'
  + '<td class="accent">' + (r.mitigation || '') + '</td>'
  + '</tr>'
).join('');

// ── Confidence Score ──────────────────────────────────────────
// Measures how much of the analysis is grounded in exec-provided data.
const inputProcs    = normInput.processes || [];
const procCount     = inputProcs.length;
const withVolume    = inputProcs.filter(p => p.volume_per_month && p.volume_per_month !== 'Not sure').length;
const withTime      = inputProcs.filter(p => p.time_per_item).length;
const denominator   = procCount || 1;

const confScore =
  (procCount > 0         ? 0.20 : 0) +
  Math.min(withVolume / denominator, 1) * 0.35 +
  Math.min(withTime   / denominator, 1) * 0.25 +
  Math.min(procCount  / 4,           1) * 0.20;

const confLevel = confScore >= 0.65 ? 'HIGH' : confScore >= 0.35 ? 'MEDIUM' : 'LOW';
const confColor = confScore >= 0.65 ? '#10b981' : confScore >= 0.35 ? '#d97706' : '#94a3b8';
const confDesc  = confScore >= 0.65
  ? 'Based primarily on your specific inputs'
  : confScore >= 0.35
  ? 'Mix of your inputs and industry benchmarks'
  : 'Primarily industry benchmarks — more detail improves accuracy';

const confidenceBadgeHTML =
  '<div class="conf-badge">'
  + '<span class="conf-dot" style="background:' + confColor + '"></span>'
  + '<span><strong style="color:' + confColor + '">' + confLevel + ' CONFIDENCE</strong>'
  + ' &nbsp;—&nbsp; <span style="color:#64748b">' + confDesc + '</span></span>'
  + '</div>';

// ── Workforce Impact ──────────────────────────────────────────
const uniqueOwners = [...new Set(roi.workflows.map(w => w.owner).filter(Boolean))];
const ownerCount   = uniqueOwners.length || 1;
const hrsPerRole   = Math.round(totalMonthlyHours / ownerCount);
const fteVal       = (s.totalAnnualHours / 2000).toFixed(1);
const ownerRoles   = uniqueOwners.slice(0, 3).join(', ');

const workforceImpactHTML =
  '<table class="impact-table"><tr>'
  + '<td><span class="impact-label">Hours freed per affected role</span>'
  + '<span class="impact-val">' + addCommas(hrsPerRole) + '/mo</span>'
  + '<span class="impact-sub">avg. across ' + ownerCount + ' role' + (ownerCount > 1 ? 's' : '') + ' doing these tasks</span></td>'
  + '<td><span class="impact-label">FTE equivalent returned</span>'
  + '<span class="impact-val">' + fteVal + '</span>'
  + '<span class="impact-sub">full-time contributors freed per year</span></td>'
  + '<td><span class="impact-label">Roles most impacted</span>'
  + '<span class="impact-val impact-roles">' + (ownerRoles || '—') + '</span>'
  + '<span class="impact-sub">regain capacity for higher-value work</span></td>'
  + '</tr></table>';

// ── Provenance ────────────────────────────────────────────────
// Pulls pain_points from analyst data (via ROI Calculator output).
// Splits clearly: what came from the exec vs what was benchmarked.
const userPainItems = painPoints
  .filter(p => p.source === 'user_stated')
  .map(p => 'Pain point — "' + (p.title || '') + '": captured directly from your submission');

const userWfItems = wfs
  .filter(w => w.source === 'user_stated')
  .map(w => 'Workflow — ' + w.name + ': selected because you identified this as a bottleneck');

// Fallback: if analyst didn't tag sources, use normInput process names
const inputProcNames = (normInput.processes || []).map(p => p.name).filter(Boolean);
const userWfNames    = wfs.filter(w => w.source === 'user_stated').map(w => w.name);
const unmatchedProcs = inputProcNames.filter(n => !userWfNames.includes(n));
const fallbackItems  = unmatchedProcs.map(n => 'Process — "' + n + '": submitted directly by your team');

const benchmarkWfItems = wfs
  .filter(w => w.source !== 'user_stated')
  .map(w => 'Workflow — ' + w.name + ' (inferred): ' + (w.rationale || 'industry-typical for this sector'));

// Filter empty strings from modeler notes
const cleanModelerNotes = modelerNotes.filter(n => typeof n === 'string' && n.trim().length > 0);

const provenanceUserItems      = [...userPainItems, ...userWfItems, ...fallbackItems];
const provenanceBenchmarkItems = [...cleanModelerNotes, ...benchmarkWfItems];

const provenanceHTML =
  '<p style="font-size:8.5pt;font-weight:bold;color:#0a1628;margin-bottom:4px">From your inputs</p>'
  + (provenanceUserItems.length
    ? '<ul class="prov-list">' + provenanceUserItems.map(l => '<li>' + l + '</li>').join('') + '</ul>'
    : '<p class="muted" style="margin-bottom:8px">No direct inputs captured — all figures are benchmark-based.</p>')
  + '<p style="font-size:8.5pt;font-weight:bold;color:#0a1628;margin:8px 0 4px">Industry benchmarks applied</p>'
  + (provenanceBenchmarkItems.length
    ? '<ul class="prov-list">' + provenanceBenchmarkItems.map(l => '<li>' + l + '</li>').join('') + '</ul>'
    : '<p class="muted">No benchmark adjustments were applied.</p>');

// ── Display object ────────────────────────────────────────────
// Flat strings only — HTML Template node reads these directly.
const display = {
  currencyCode:   roi.currency.code,
  currencySymbol: sym,
  coverHeadline:  fmt(totalMonthlyHours) + ' hrs returned & ' + short(tf12) + ' total financial gain — 12-month conservative estimate',

  // Stat cards
  statHours:    fmt(s.totalAnnualHours),
  statHoursSub: fmt(totalMonthlyHours),
  statOD:       short(s.operationalDividend12mo),
  statTF:       short(tf12),
  statFTE:      (s.totalAnnualHours / 2000).toFixed(1),

  // Outcomes (full precision)
  totalAnnualHours:  fmt(s.totalAnnualHours),
  totalMonthlyHours: fmt(totalMonthlyHours),
  od12:     cur(s.operationalDividend12mo),
  pu12:     cur(s.profitUplift12mo),
  tf12:     cur(tf12),
  payback:  s.paybackMonths != null ? String(s.paybackMonths) + ' months' : '—',

  // Multi-year ramp (Y2 = 2.15×, Y3 = 3.40×)
  hrs24: fmt(Math.round(s.totalAnnualHours * 2.15)),
  od24: cur(s.operationalDividend24mo),
  pu24: cur(s.profitUplift24mo),
  tf24: cur(s.totalFinancialGain24mo),
  hrs36: fmt(Math.round(s.totalAnnualHours * 3.40)),
  od36: cur(s.operationalDividend36mo),
  pu36: cur(s.profitUplift36mo),
  tf36: cur(s.totalFinancialGain36mo),

  // Company snapshot
  employeesDisplay: roi.employees ? addCommas(roi.employees) + ' (est. midpoint)' : 'Not specified',
  revenueDisplay:   roi.revenue   ? sym + String(roi.revenue) + 'M (est. midpoint)' : 'Not specified',

  // Pre-built HTML blocks
  execSummaryHTML,
  confidenceBadgeHTML,
  workforceImpactHTML,
  scopeListHTML,
  asisTableBody,
  bvaTableBody,
  profitLeversBody,
  deployTableBody,
  functionRollupBody,
  risksTableBody,
  provenanceHTML,
  cta: writerOut.cta_paragraph || ('Let us show you how we can return ' + fmt(totalMonthlyHours) + ' hours to your team each month.'),
};

return [{ json: {
  roi_data:        roi,
  copy:            writerOut,
  display,
  current_date:    currentDate,
  recipient_email: normInput.email || '',
}}];
